#!/bin/bash
set -e
PAYLOAD=''
TARGET_DIR="$HOME/trend-crawler"
if [ ! -d "$TARGET_DIR" ]; then echo "Error: $TARGET_DIR が見つかりません"; exit 1; fi
echo "$PAYLOAD" | base64 -d | tar -xzf - -C "$TARGET_DIR"
echo "✅ ファイルを更新しました"
cd "$TARGET_DIR"
git add topics.yaml agents/summarize_agent.py agents/export_agent.py main.py CLAUDE.md
git commit -m "feat: トピック変更・Gemini移行・出力フォーマット刷新"
git push origin master
echo "✅ GitHub にプッシュ完了"
